description:
Aggregate function group by primary key/non-primary key has differnet result
How to repeat:
create table t1(a int primary key, b set('Alice','Bob') DEFAULT NULL);
insert into t1 value(1,'Bob');
select max(b) + 0 from t1 group by a;
+------------+
| max(b) + 0 |
+------------+
|          0 |
+------------+

create table t2(a int, b set('Alice','Bob') DEFAULT NULL);
insert into t2 value(1,'Bob');
select max(b) + 0 from t2 group by a;
+------------+
| max(b) + 0 |
+------------+
|          2 |
+------------+
